@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>Dispatch Dashboard</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">Refresh</button>
    </div>
</div>

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match your filter.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            (string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Customer")]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="mb-4 row">
    <div class="col-md-5">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment">
                Track
            </button>
        </div>
    </div>
</div>

@if (isSearching)
{
    <p><em>Searching...</em></p>
}
else if (searchPerformed && trackedShipment == null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@searchedNumber</strong>".
    </div>
}
else if (trackedShipment != null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment @trackedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span></dd>
                        <dt>Description</dt>
                        <dd>@trackedShipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@trackedShipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@trackedShipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@trackedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                        @if (trackedShipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success">@trackedShipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

<h2 class="mt-4">My Shipments</h2>

@if (myShipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p>You have no shipments.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in myShipments)
            {
                <tr class="cursor-pointer" @onclick="() => SelectShipment(shipment)">
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? trackedShipment;
    private List<Shipment>? myShipments;
    private bool isSearching;
    private bool searchPerformed;

    [CascadingParameter]
    private Task<Microsoft.AspNetCore.Components.Authorization.AuthenticationState>? AuthState { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (AuthState != null)
        {
            var state = await AuthState;
            var email = state.User.Identity?.Name ?? string.Empty;
            myShipments = await ShipmentService.GetShipmentsForCustomerAsync(email);
        }
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchPerformed = true;
        searchedNumber = trackingNumber;
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber);
        isSearching = false;
    }

    private void SelectShipment(Shipment shipment)
    {
        trackedShipment = shipment;
        trackingNumber = shipment.TrackingNumber;
        searchPerformed = true;
        searchedNumber = shipment.TrackingNumber;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };
}

