using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public static class DataSeeder
{
    public static async Task SeedAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        // Seed roles
        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
            {
                await roleManager.CreateAsync(new IdentityRole(role));
            }
        }

        // Seed demo users
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();

        await EnsureUser(userManager, "dispatcher@shipmenttracker.com", "Dispatch1!", "Dispatcher");
        await EnsureUser(userManager, "customer@shipmenttracker.com", "Customer1!", "Customer");

        // Seed shipments
        if (!await db.Shipments.AnyAsync())
        {
            db.Shipments.AddRange(
                new ShipmentEntity
                {
                    TrackingNumber = "ST-100001",
                    Origin = "New York, USA",
                    Destination = "London, UK",
                    Status = 2, // InTransit
                    CustomerEmail = "customer@shipmenttracker.com",
                    Description = "Electronics - Laptop",
                    ShippedDate = DateTime.UtcNow.AddDays(-3),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(4)
                },
                new ShipmentEntity
                {
                    TrackingNumber = "ST-100002",
                    Origin = "Shanghai, China",
                    Destination = "Berlin, Germany",
                    Status = 1, // PickedUp
                    CustomerEmail = "customer@shipmenttracker.com",
                    Description = "Furniture - Office Desk",
                    ShippedDate = DateTime.UtcNow.AddDays(-1),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(12)
                },
                new ShipmentEntity
                {
                    TrackingNumber = "ST-100003",
                    Origin = "Tokyo, Japan",
                    Destination = "Sydney, Australia",
                    Status = 3, // OutForDelivery
                    CustomerEmail = "other@example.com",
                    Description = "Auto Parts",
                    ShippedDate = DateTime.UtcNow.AddDays(-5),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(1)
                },
                new ShipmentEntity
                {
                    TrackingNumber = "ST-100004",
                    Origin = "Los Angeles, USA",
                    Destination = "Toronto, Canada",
                    Status = 4, // Delivered
                    CustomerEmail = "customer@shipmenttracker.com",
                    Description = "Books - Bulk Order",
                    ShippedDate = DateTime.UtcNow.AddDays(-7),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
                    ActualDelivery = DateTime.UtcNow.AddDays(-2)
                },
                new ShipmentEntity
                {
                    TrackingNumber = "ST-100005",
                    Origin = "Mumbai, India",
                    Destination = "Dubai, UAE",
                    Status = 5, // Delayed
                    CustomerEmail = "other@example.com",
                    Description = "Textiles",
                    ShippedDate = DateTime.UtcNow.AddDays(-4),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(2)
                }
            );
            await db.SaveChangesAsync();
        }
    }

    private static async Task EnsureUser(UserManager<ApplicationUser> userManager, string email, string password, string role)
    {
        if (await userManager.FindByEmailAsync(email) == null)
        {
            var user = new ApplicationUser
            {
                UserName = email,
                Email = email,
                EmailConfirmed = true
            };
            await userManager.CreateAsync(user, password);
            await userManager.AddToRoleAsync(user, role);
        }
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            return await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => MapToModel(s))
                .ToListAsync();
        }).RequireAuthorization("DispatcherPolicy");

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return entity == null ? Results.NotFound() : Results.Ok(MapToModel(entity));
        });

        group.MapGet("/customer/{email}", async (string email, ApplicationDbContext db) =>
        {
            return await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => MapToModel(s))
                .ToListAsync();
        });

        group.MapPut("/{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity == null) return Results.NotFound();

            entity.Status = (int)status;
            if (status == ShipmentStatus.Delivered)
            {
                entity.ActualDelivery = DateTime.UtcNow;
            }
            await db.SaveChangesAsync();
            return Results.NoContent();
        }).RequireAuthorization("DispatcherPolicy");
    }

    private static Shipment MapToModel(ShipmentEntity entity) => new()
    {
        Id = entity.Id,
        TrackingNumber = entity.TrackingNumber,
        Origin = entity.Origin,
        Destination = entity.Destination,
        Status = (ShipmentStatus)entity.Status,
        CustomerEmail = entity.CustomerEmail,
        Description = entity.Description,
        ShippedDate = entity.ShippedDate,
        EstimatedDelivery = entity.EstimatedDelivery,
        ActualDelivery = entity.ActualDelivery
    };
}

